//-https://bananarepublic.gap.com/browse/product.do?pid=624065052&vid=1&searchText=Chino#pdp-page-content

const utils = optimizely.get('utils');
const campState = __OPTLY_STATE__.shared.init('boldMetrics');

const campVars = campState.cache.variables;
campVars.selectors = {
  targetElement: '.size-guide-button-text',
};
campVars.catIDs = [];
campVars.copy = {};

campVars.pageProductInfo = window.__PRODUCT_PAGE_STATE__.initialProductData;

const campFuncs = campState.cache.functions;
campFuncs.utils = {};

campFuncs.pullProductIdFromURL = () => {
  const urlParams = new URLSearchParams(window.location.search);
  campVars.pid = urlParams.get('pid');
  if (campVars.pid && campVars.pid.length >= 9) {
    campVars.styleId = campVars.pid.substring(0, 6);

    campVars.ccId = campVars.pid.substring(0, 9);
    return {
      ccid: campVars.ccId,
      styleId: campVars.styleId,
    };
  }
};

campFuncs.addBoldMetricsButton = (product) => {
  utils.waitForElement(campVars.selectors.targetElement).then((elem) => {
    if (!document.querySelector('.boldmetrics-button')) {
      const bmWrapper = document.createElement('div');
      bmWrapper.className = 'dpg-right-side-eles flex';

      const btn = document.createElement('button');
      btn.id = 'boldmetrics-ssc-default';
      btn.setAttribute('data-garment', product.styleId);
      btn.setAttribute('data-background-color', '#FFFFFF');
      btn.className = 'boldmetrics-button-wrapper';

      bmWrapper.appendChild(btn);

      // insertElement
      elem.insertAdjacentElement('beforeBegin', bmWrapper);
      bmWrapper.appendChild(elem);
    }
  });

  utils.waitForElement('#boldmetrics-ssc-default').then((bmBtn) => {
    bmBtn.addEventListener('click', (e) => {
      __OPTLY_STATE__.shared.sendMetric('boldmetrics_button_clicked');
    });
  });
};

campFuncs.scrapPrice = () => {
  const salePriceElem = document.querySelector('.current-sale-price');
  let price = null;
  if (salePriceElem) {
    const priceText = salePriceElem.innerText.replace(/[^0-9.]/g, '');
    price = parseFloat(priceText);
  } else {
    const regularPriceElem = document.querySelector('.current-regular-price');
    if (regularPriceElem) {
      const priceText = regularPriceElem.innerText.replace(/[^0-9.]/g, '');
      price = parseFloat(priceText);
    }
  }
  return price;
};

campFuncs.normalizeDivision = (style) => {
  const divMap = (campVars.divisionMap = {
    'GAP WOMENS': 'womens',
    'GAP MENS': 'mens',
    MENS: 'mens',
    WOMENS: 'womens',
  });

  return divMap[style.merchandise_hierarchy.division_description];
};

campFuncs.normalizeCategory = (style) => {
  campState.log('Category ID: ');
  campState.log(style.primary_category_id);

  campVars.categoryMap = {
    5664: 'bottoms',
    35878: 'bottoms',
  };
  return campVars.categoryMap[style.primary_category_id] || 'bottoms';
};
campFuncs.parseVariantKeyFromID = (selectedVariant) => {
    const splitVariantId = selectedVariant.id.split('_');
    const parsedVariant = splitVariantId[splitVariantId.length - 1];
    return parsedVariant;
}

campFuncs.scrapActiveVariant = (variantHeaderText) => {
  const allVariantCategoryHeaders = Array.from(document.querySelectorAll('.pdp_variant-selector-wrapper [data-testid="pdp-variant-label"]'));
  const matchingHeader = allVariantCategoryHeaders.find(header => header.innerText.trim() === variantHeaderText);
  if (matchingHeader) {
    const selectedVariant = matchingHeader.parentElement.parentElement.querySelector('[data-selected="true"]');
    if (selectedVariant) {
      return campFuncs.parseVariantKeyFromID(selectedVariant);
    } else {
      campState.log('No selected variant found for header: ' + variantHeaderText);
      return undefined;
    }
  }
};

campFuncs.scrapActiveVariants = () => {
  const allVariants = campVars.pageProductInfo.variant_definition;
  debugger;
  if (allVariants.length > 0) {

    allActiveVariantKeys = allVariants.map((variant) => {
      if (variant.values.length === 1) {
        return variant.values[0].id;
      } else if (variant.values.length > 1) {
        campState.log('Multiple options for variant category: ' + variant.name);
        return campFuncs.scrapActiveVariant(variant.name);
      }
    });

    return allActiveVariantKeys;;
  } else {
    // If only one variant available pull from initialProductData object
    return [__PRODUCT_PAGE_STATE__.initialProductData.selectedMultiVariantKey];
  }
};

campFuncs.gatherProductInfo = () => {
  const product = (campVars.prodInfo = {});
  const pds = campVars.pageProductInfo;
  const ids = campFuncs.pullProductIdFromURL(); // sets campVars.pid and styleId
  campState.log('Product ID: ' + JSON.stringify(ids));
  const style = pds.styles[ids.styleId];

  product.title = style.description;

  const division = campFuncs.normalizeDivision(style);
  const category = campFuncs.normalizeCategory(style);

  product.styleId = ids.styleId;

  product.price = campFuncs.scrapPrice();

  product.sizechart = `${division}_${category}`;
  product.type = `${style.merchandise_hierarchy.division_description} > ${style.primary_category_name}`;

  const selectedVariantKeys = campFuncs.scrapActiveVariants();
  campState.log('Selected Variants: ' + JSON.stringify(selectedVariantKeys));
  const selectedVariantKey = selectedVariantKeys.length > 1 ? selectedVariantKeys.join('|') : selectedVariantKeys[0];
  const selectedVariant = pds.variants[selectedVariantKey];

  if (selectedVariant && selectedVariant.customer_choices) {
    const selectedCC = selectedVariant.customer_choices[ids.ccid];
    if (!selectedCC) {
      campState.log('No selected customer choice found for ' + ids.ccid);
      return;
    }
    product.variants = selectedCC.skus.map((sku) => {
      return {
        id: sku.sku_id,
        size: sku.description,
        available: sku.isInstock,
        sku: sku.sku_id,
      };
    });
    return product;
  }
};

campFuncs.parseSizeToDimensions = (size) => {
  // Parse size string like '28 Regular-Regular' into components
  const parts = size.split(' ');

  if (parts.length >= 2) {
    const dimension1 = parts[0]; // '28'
    const dimension2 = parts[1]; // 'Regular-Regular'

    if (dimension2.includes('-')) {
      // Split fit and inseam by hyphen
      const fitInseamParts = dimension2.split('-');
      let seconddimension = '';
      let fit = '';

      if (fitInseamParts[0].match(/\d+/)) {
        // If the first part contains a number, it's the inseam
        seconddimension = fitInseamParts[0] || '';
        fit = fitInseamParts[1] || '';
      } else {
        seconddimension = fitInseamParts[1] || '';
        fit = fitInseamParts[0] || '';
      }

      return {
        dimension1: dimension1,
        fit: fit || '', // 'Regular'
        dimension2: seconddimension || '', // '28'
      };
    } else {
      return {
        dimension1: dimension1,
        fit: dimension2,
        dimension2: dimension2,
      };
    }
  }

  // Fallback for malformed strings
  return {
    dimension1: size,
    fit: '',
    dimension2: '',
  };
};

campFuncs.addBoldMetrics = () => {
  const prodInfo = campFuncs.gatherProductInfo();
  if (!prodInfo) {
    campState.log('Failed to gather product info, aborting Bold Metrics setup.');
    return;
  }
  window._boldmetrics = {
    locale: 'en-US',
    //softlaunch: true,
    product: {
      //Required
      id: prodInfo.styleId,
      type: prodInfo.type,
      price: prodInfo.price,
      title: prodInfo.title,
      sizechart: prodInfo.sizechart,
      variants: prodInfo.variants,
    },
  };

  campFuncs.addBoldMetricsButton(prodInfo);

  utils.waitForElement('.dpg-right-side-eles').then((bmBtn) => {
    __OPTLY_STATE__.shared.addScript(
      'https://d2hicexbdkkc9q.cloudfront.net/ssc.production.js',
      'boldmetrics-script'
    );
  });

  document.addEventListener('bmi_add_to_cart', (e) => {
    campState.log(`bmi_add_to_cart - ${JSON.stringify(e.detail.size)}`);

    const size = campFuncs.parseSizeToDimensions(e.detail.size);
    if (size.fit) {
      const fitButton = document.querySelector(
        `#pdp_variant_${size.fit.toUpperCase()}`
      );

      if (fitButton) {
        fitButton.click();
      }
    }

    if (size.dimension1) {
      const dimension1Button = document.querySelector(
        `#pdp_buybox_dimension_${size.dimension1}`
      );
      if (dimension1Button) {
        dimension1Button.click();
      }
    }

    if (size.dimension2) {
      const dimension2Button = document.querySelector(
        `#pdp_buybox_dimension_${size.dimension2}`
      );
      if (dimension2Button) {
        dimension2Button.click();
      }
    }
  });
};

campFuncs.main = () => {
  campState.log('in main');
  const isOOS = document.querySelector('.out-of-stock-page');
  if (!isOOS) {
    campFuncs.addBoldMetrics();
  } else {
    campState.log('Product is out of stock, not adding Bold Metrics button.');
  }
};

campFuncs.main();
