const isPDPRedesign = true; // () => document.cookie.indexOf('br191-a') !== -1;
utils.waitForElement('[data-test-id="recs-carousel-0"]').then(recCarousel => {
  recCarousel.classList.add('dpg-top-rec');
	const product = document.querySelector('#product-page');
  const pdpContentWrapper = document.querySelector('#product-page');
  if (product) {
  	product.insertAdjacentElement("afterbegin", recCarousel);
  }

  if (pdpContentWrapper) {
    if (isPDPRedesign()) {
      	pdpContentWrapper.classList.add('dpg-pdp-redesign')
    }
  }
  const recTopAdjustment = isPDPRedesign() ? 100 : 30;
  var recTop = window.pageYOffset + recCarousel.getBoundingClientRect().top - recTopAdjustment;
 
  window.scrollTo(0, recTop);
  
	var buyBoxWrapper = document.querySelector('#buy-box-wrapper-id');
	var preventClass = 'dpg_prevent-over-scroll';
	var stickyTop = window.pageYOffset + document.querySelector('.l--sticky-wrapper').getBoundingClientRect().top;

	const updateBuyBoxClass = function (e) {
		if (window.scrollY > stickyTop) {
			buyBoxWrapper.classList.remove(preventClass);
		} else {
			buyBoxWrapper.classList.add(preventClass);
		}
	}

	window.addEventListener('scroll', updateBuyBoxClass)
});
