campVars.sessionKey = 'aiuta_tooltip_shown';

const aiutaId = 'dpg-aiuta-container';

const isMobile =
  __OPTLY_STATE__.shared.constants.breakpoint == 'desktop' ? false : true;

const campFuncs = campState.cache.functions;
campFuncs.utils = {};

campFuncs.get9DigitPIDFromURL = () => {
  const pidParam = new URLSearchParams(window.location.search).get('pid');
  return pidParam ? pidParam.substring(0, 9) : null;
};

campFuncs.utils.getSess = () => {
  return sessionStorage.getItem(campVars.sessionKey);
};
campFuncs.utils.incrementTooltipViewCount = () => {
  const curVal = campFuncs.utils.getSess();
  if (!curVal) {
    sessionStorage.setItem(campVars.sessionKey, '1');
  } else {
    const newVal = parseInt(curVal, 10) + 1;
    sessionStorage.setItem(campVars.sessionKey, newVal.toString());
  }
};

