campFuncs.launchAiuta = () => {
  campState.log('In Init Function');
  const aiuta = window.AiutaInstance || campFuncs.initializeAiuta();

  aiuta.tryOn(campFuncs.get9DigitPIDFromURL());
};

campFuncs.tooltipHide = () => {
  // Implementation for hiding tooltip
  const tooltip = document.querySelector('.odi-tooltip');
  if (tooltip) {
    tooltip.style.opacity = '0';
  }
};

campFuncs.tooltipShow = () => {
  // Implementation for showing tooltip
  const sessCount = campFuncs.utils.getSess();
  if (!sessCount || parseInt(sessCount, 10) < 2) {
    const tooltip = document.querySelector('.odi-tooltip');
    if (tooltip) {
      tooltip.style.opacity = '1';
      campFuncs.utils.incrementTooltipViewCount();

      document.body.addEventListener('click', () => {
      setTimeout(campFuncs.tooltipHide(), 750);
    });
    }
  }
};

campFuncs.aiutaButtonHandler = (e) => {
  e.preventDefault();
  e.stopPropagation();

  campFuncs.launchAiuta();
  campFuncs.tooltipHide();
};

campFuncs.buildAiutaButton = () => {
  const aiutaButton = document.createElement('div');
  aiutaButton.id = aiutaId;
  aiutaButton.innerHTML = `<a href="#">${campVars.iconSVG}<span class="odi-tooltip">${campVars.copy.buttonText}</span></a>`;

  aiutaButton.addEventListener('click', campFuncs.aiutaButtonHandler);

  setTimeout(() => {
    campFuncs.tooltipShow();
  }, 50);

  return aiutaButton;
};

