campFuncs.addButton = () => {
  const pid = campFuncs.get9DigitPIDFromURL();
  console.log('PID:', pid);
  if (!campFuncs.isAiutaProduct(pid)) {
    campState.log(`pid ${pid} Not an Aiuta product`);
    return;
  }

  if (document.getElementById(aiutaId)) {
    campState.log('Aiuta Button already exists');
    return;
  }

  const firstPhoto = isMobile
    ? document.querySelector('.pdp_carousel__slide')
    : document.querySelector('#gallery-wrapper img:first-child');

  if (firstPhoto) {
    if (isMobile) {
      firstPhoto.insertAdjacentElement(
        'beforeend',
        campFuncs.buildAiutaButton()
      );
    } else {
      firstPhoto.insertAdjacentElement(
        'afterend',
        campFuncs.buildAiutaButton()
      );
    }
  }
};

campFuncs.main = () => {
  campState.log('In Main Function');
  sharedFuncs.addScript(
    'https://static.aiuta.com/sdk/v1.0.0/index.umd.js',
    'aiuta-script'
  );

  utils
    .waitUntil(() => {
      return window.Aiuta;
    })
    .then(() => {
      campFuncs.addButton();

      utils.observeSelector('.pdp_carousel__slide', () => {
        setTimeout(() => {
          campFuncs.addButton();
        }, 250);
      });
    });
};

campFuncs.main();
