const brandLogos = [
  {
    'brandName': 'Gap Factory',
    'imgSrc': gapFactorySVG,
    'href': 'https://www.gapfactory.com/',
    //'ssiteID': ''
  },
  {
    'brandName': 'Banana Republic Factory',
    'imgSrc': brFactorySVG,
    'href': 'https://bananarepublicfactory.gapfactory.com/',
    //'ssiteID': ''
  },
];

const buildBrandBar = () => {
  //const bar = document.createElement('div');
  //bar.className = "mx-auto flex h-10 items-center justify-center md:max-w-[1044px] sm:m-auto sm:justify-between";

  const flexWrapper = document.createElement('div');
  flexWrapper.className = 'flex items-center';

  //bar.appendChild = flexWrapper
  
  for (let index = 0; index < brandLogos.length; index++) {
    const logoImg = brandLogos[index];
    flexWrapper.appendChild(itemWrapper(logoImg))
  }

  return flexWrapper;
}

const itemWrapper = (img) => {  
  const logoItem = document.createElement('div');
  logoItem.className = 'mx-2 flex-shrink-0';
  logoItem.innerHTML = `<a href="${img.href}" target="_self"><span aria-hidden="true" class="dpg-logo_wrapper flex relative h-auto w-auto min-h-auto min-w-auto ">${img.imgSrc}</span></a>`
  return logoItem;
}

const header = document.querySelector('header [data-testid="brand-logo-gap"]').parentElement
header.style.display = 'none';

header.insertAdjacentElement('beforeBegin', buildBrandBar());
