  const utils = optimizely.get("utils");
  testObj.log("campaign start");
    testObj.log("in qa");

  const findmineSelector = "findmine-app-container";
  const findmineButtonSelector = "dpg-shopThisLookbtn";

  let isMobile = false;
  if (window.innerWidth < 1024) {
    isMobile = true;
    testObj.log("isMobile found");
  }

  const hasFindMineContainer = findmine => { return findmine && findmine.innerText.trim() !== ""; }

  const createShopThisLook = (findmine) => {
    const shopThisLook = document.createElement("div");
    shopThisLook.id = findmineButtonSelector;
    shopThisLook.innerHTML = '<a href="#">Shop This Look</a>';
    shopThisLook.style.display = "none"; // hidden by default;
    shopThisLook.onclick = function (e) {
      e.preventDefault();
      e.stopPropagation();

      const findmine = document.getElementById(findmineSelector);
      if(findmine) {
          window.scrollTo(0, findmine.offsetTop - 150);
          __OPTLY_STATE__.shared.sendMetric('findminecta');
      }
    };
    return shopThisLook;
  };

  const hideShowFindMine = () => {
    testObj.log("find mine container updated'");
    const findMineButton = document.getElementById(findmineButtonSelector);
    if(findMineButton) {
        if (hasFindMineContainer(document.getElementById(findmineSelector))) {
            findMineButton.style.display = "";
        } else {
            findMineButton.style.display = "none";
        }
    }
}

  const insertShopThisLook = (findmine) => {
      const firstPhoto = isMobile
    ? document.querySelector(".pdp_carousel__slide")
    : document.querySelector("#gallery-wrapper img:first-child");
    
    if (firstPhoto) {
        if (isMobile) {
          firstPhoto.insertAdjacentElement("beforeend", createShopThisLook());
        } else {
          firstPhoto.insertAdjacentElement("afterend", createShopThisLook());
        }

        if (hasFindMineContainer(findmine)) {
          hideShowFindMine()
        }
      }
      
  }

  utils.waitForElement('#' + findmineSelector).then((findmine) => {
    var observer = new MutationObserver(() => {
      hideShowFindMine()
    });
  
    observer.observe(findmine, {
      childList: true,
      subtree: true
    });

    insertShopThisLook(findmine);
  })

  const colorSwatches = document.querySelectorAll(".swatch");
  if (colorSwatches) {
    for (let index = 0; index < colorSwatches.length; index++) {
      const colorSwatch = colorSwatches[index];
      colorSwatch.addEventListener("click", function () {
        setTimeout(function () {
          const findMineButton = document.getElementById(findmineButtonSelector);
          if (findMineButton) {
              const next = findMineButton.nextElementSibling;
              if (next && next.tagName === "IMG") {
                  next.insertAdjacentElement("afterend", findMineButton);
              }
          } else {
            insertShopThisLook(document.getElementById(findmineSelector));
          }
        }, 50);
      });
    }
  }
