const utils = window.optimizely.get('utils');
const breakpoint = window.__OPTLY_STATE__.shared.constants.breakpoint;

utils
  .waitUntil(
    () =>
      document.querySelector('#loyalty') && document.querySelector('#promos')
  )
  .then(() => {
    if (breakpoint === 'desktop') {
      // points & rewards module
      const pointsModule = document.querySelector('#loyalty');
      // promos module
      const promosModule = document.querySelector('#promos');
      // move points & rewards module module before promos
      promosModule.before(pointsModule);
    }
  });
