(function () {
  const targetSelector = '[data-testid="promo-desc"] p';

  function stripGreeting(p) {
    if (!p) return;
    const br = p.querySelector("br");
    if (!br) return;

    let node = p.firstChild;
    while (node && node !== br) {
      const next = node.nextSibling;
      if (node.nodeType === Node.TEXT_NODE) node.remove();
      node = next;
    }
    br.remove(); // remove the line break too
  }

  function run() {
    const p = document.querySelector(targetSelector);
    if (p) stripGreeting(p);
  }

  run();

  const observer = new MutationObserver(() => run());
  observer.observe(document.documentElement, {
    childList: true,
    subtree: true,
    characterData: true
  });
})();
