campVars.executionCount = campVars.executionCount || 0;


const campFuncs = campState.cache.functions;

function debounce(func, delay) {
    let timeout;
    return function (...args) {
        clearTimeout(timeout);
        timeout = setTimeout(() => {
            func.apply(this, args);
        }, delay);
    };
}

campFuncs.main = () => {
  campVars.executionCount++;
  const pageType = window.gap.pageType;
  const message = `Page type is ${pageType}; Count is: ${campVars.executionCount}`;
  campState.log(message);
  console.log(message);
};

const unload = utils.observeSelector('[data-testid="deprecated-sticky"]',debounce(campFuncs.main, 500));

