if (window.__OPTLY_STATE__.shared.constants.breakpoint === "desktop") {
  const CAPTURE = true; // keep add/remove consistent

  const createHoverFunc = (productImageContainer) => {
    setTimeout(() => {
      if (!productImageContainer) return;

      const productParentContainer = productImageContainer.closest('.plp_product-card');
      const plpProductImageContainer = productImageContainer.querySelector('.plp_product-image__carousel-viewport');
      if (!productParentContainer) return;

      const imgCount = productImageContainer.querySelectorAll('img').length;
      let nextButton = productImageContainer.querySelector('#button_icon_carousel_chevron_next');
      let image1 = productImageContainer.querySelector('[data-image-index="0"]');
      let image2 = productImageContainer.querySelector('[data-image-index="1"]');

      // If we can’t address 0/1 explicitly, don’t wire hover
      if (imgCount > 1 && (!image1 || !image2)) return;

      const doubleClick = () => {
        // re-query defensively in case DOM swapped
        image1 = productImageContainer.querySelector('[data-image-index="0"]') || image1;
        image2 = productImageContainer.querySelector('[data-image-index="1"]') || image2;
        nextButton = productImageContainer.querySelector('#button_icon_carousel_chevron_next') || nextButton;

        if (!image1 || !image2 || !nextButton) return;

        image1.style.left = '-100%';
        image2.style.left = '0px';
        if (typeof nextButton.click === 'function') nextButton.click();

        nextButton.removeEventListener('click', doubleClick, CAPTURE);
        nextButton.classList.remove('dblclk_aak-1');
      };

      const removeHoverFuncs = () => {
        if (plpProductImageContainer) {
          plpProductImageContainer.removeEventListener('mouseenter', hoverInHandler, CAPTURE);
          plpProductImageContainer.removeEventListener('mouseleave', hoverOutHandler, CAPTURE);
        }
        const nb = productImageContainer.querySelector('#button_icon_carousel_chevron_next');
        if (nb) nb.removeEventListener('mouseenter', hoverInHandler, CAPTURE);
      };

      const hoverInHandler = () => {
        // re-query slides defensively
        image1 = productImageContainer.querySelector('[data-image-index="0"]') || image1;
        image2 = productImageContainer.querySelector('[data-image-index="1"]') || image2;
        if (!image1 || !image2) return;

        image1.style.left = '-100%';
        image2.style.left = '0px';

        nextButton = productImageContainer.querySelector('#button_icon_carousel_chevron_next') || nextButton;
        if (!nextButton) return;

        if (!nextButton.classList.contains('dblclk_aak-1')) {
          nextButton.addEventListener('click', doubleClick, CAPTURE);
          nextButton.classList.add('dblclk_aak-1');
        }
        nextButton.addEventListener('mouseenter', hoverInHandler, CAPTURE);
        nextButton.addEventListener('click', removeHoverFuncs, CAPTURE);
      };

      const hoverOutHandler = () => {
        // re-query slides defensively
        image1 = productImageContainer.querySelector('[data-image-index="0"]') || image1;
        image2 = productImageContainer.querySelector('[data-image-index="1"]') || image2;
        if (!image1 || !image2) return;

        image1.style.left = '0px';
        image2.style.left = '100%';

        nextButton = productImageContainer.querySelector('#button_icon_carousel_chevron_next') || nextButton;
        if (nextButton) {
          nextButton.removeEventListener('click', removeHoverFuncs, CAPTURE);
        }
      };

      if (imgCount > 1 && plpProductImageContainer) {
        plpProductImageContainer.addEventListener('mouseenter', hoverInHandler, CAPTURE);
        plpProductImageContainer.addEventListener('mouseleave', hoverOutHandler, CAPTURE);
      }

      // Swatch (variant) changes
      const swatches = productParentContainer.querySelectorAll('.fds_selector-swatch__input-container');
      swatches.forEach((swatch) => {
        swatch.addEventListener('click', (event) => {
          removeHoverFuncs();

          const card = event.target && event.target.closest
            ? event.target.closest('.plp_product-card')
            : null;
          if (!card) return;

          const newProductColorContainer = card.querySelector('.plp_product-image');
          if (!newProductColorContainer) return;

          newProductColorContainer.classList.remove('gppd-test_aak-1');
          addAltImageTestDesk(newProductColorContainer); // harmless extra arg
        });
      });
    });
  };

  const addAltImageTestDesk = () => {
    const plpProducts = document.querySelectorAll('.plp_product-image');
    plpProducts.forEach((productImageContainer) => {
      if (!productImageContainer.classList.contains('gppd-test_aak-1')) {
        createHoverFunc(productImageContainer);
        productImageContainer.classList.add('gppd-test_aak-1');
      }
    });
  };

  const plpGrid = document.querySelector('.product-grid');
  const plpMOConfig = { subtree: true, childList: true };

  const plpMutationObserver = new MutationObserver(() => {
    addAltImageTestDesk();
  });

  if (plpGrid) {
    plpMutationObserver.observe(plpGrid, plpMOConfig);
  }

  addAltImageTestDesk();
}
